class ResumeGenerator:
 def __init__(self) -> None:
 self.client = CohereClient()

 def generate_structured_resume(
 self,
 job_description: str,
 requirements: JobRequirements,
 evidence: list[RetrievedEvidence],
 ) -> dict[str, Any]:
