 {/* Education */}
 {education.length > 0 && (
 <section id="education">
 <SectionTitle theme={t}>Education</SectionTitle>
 <div className="flex flex-col gap-6 mt-4">
 {education.map((edu) => (
 <div key={edu._id} className={`rounded-2xl p-6 border ${t.card} shadow-sm`}>
