import { useState, useEffect } from 'react'
import { getExperiences, createExperience, updateExperience, deleteExperience } from '../../services/workExperience'
import { useToast } from '../../context/ToastContext'

interface WorkExperience {
 _id: string
 company: string
 role: string
 startDate: string
 endDate: string
 current: boolean
 description: string
 source: string
}

const empty = {
 company: '', role: '', startDate: '',
 endDate: '', current: false, description: ''
}

export default function WorkExperienceSection() {
 const { showToast } = useToast()
 const [experiences, setExperiences] = useState<WorkExperience[]>([])
 const [adding, setAdding] = useState(false)
 const [editingId, setEditingId] = useState<string | null>(null)
 const [form, setForm] = useState(empty)

 useEffect(() => {
 getExperiences().then(res => setExperiences(res.data.data))
 }, [])

 const resetForm = () => { setForm(empty); setAdding(false); setEditingId(null) }

 const handleSubmit = async (e: React.FormEvent) => {
 e.preventDefault()
 try {
 if (editingId) {
 const res = await updateExperience(editingId, form)
 setExperiences(prev => prev.map(e => e._id === editingId ? res.data.data : e))
 showToast('Experience updated')
 } else {
 const res = await createExperience(form)
 setExperiences(prev => [res.data.data, ...prev])
 showToast('Experience added')
 }
 resetForm()
 } catch {
 showToast('Failed to save experience', 'error')
 }
 }

 const handleEdit = (exp: WorkExperience) => {
 setEditingId(exp._id)
 setForm({ company: exp.company, role: exp.role, startDate: exp.startDate, endDate: exp.endDate, current: exp.current, description: exp.description })
 setAdding(true)
 }

 const handleDelete = async (_id: string) => {
 try {
 await deleteExperience(_id)
 setExperiences(prev => prev.filter(e => e._id !== _id))
 showToast('Experience deleted')
 } catch {
 showToast('Failed to delete', 'error')
 }
 }

 return (
 <div className="bg-gray-900 rounded-2xl p-6">
 <div className="flex items-center justify-between mb-6">
 <div>
 <h2 className="text-xl font-semibold">Work Experience</h2>
 <p className="text-xs text-gray-500 mt-1">Your work history</p>
 </div>
 {!adding && (
 <button
 onClick={() => setAdding(true)}
 className="text-sm text-indigo-400 hover:text-indigo-300 transition"
 >
 + Add
 </button>
 )}
 </div>

 {/* Form */}
 {adding && (
 <form onSubmit={handleSubmit} className="flex flex-col gap-4 mb-6 pb-6 border-b border-gray-800">
 <div className="grid grid-cols-2 gap-4">
 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">Company</label>
 <input
 value={form.company}
 onChange={e => setForm(prev => ({ ...prev, company: e.target.value }))}
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 />
 </div>
 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">Role</label>
 <input
 value={form.role}
 onChange={e => setForm(prev => ({ ...prev, role: e.target.value }))}
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 />
 </div>
 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">Start Date</label>
 <input
 type="month"
 value={form.startDate}
 onChange={e => setForm(prev => ({ ...prev, startDate: e.target.value }))}
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 />
 </div>
 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">End Date</label>
 <input
 type="month"
 value={form.endDate}
 disabled={form.current}
 onChange={e => setForm(prev => ({ ...prev, endDate: e.target.value }))}
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500 disabled:opacity-40"
 />
 </div>
 <div className="col-span-2 flex items-center gap-2">
 <input
 type="checkbox"
 id="current"
 checked={form.current}
 onChange={e => setForm(prev => ({ ...prev, current: e.target.checked, endDate: '' }))}
 className="accent-indigo-500"
 />
 <label htmlFor="current" className="text-xs text-gray-400">I currently work here</label>
 </div>
 <div className="col-span-2 flex flex-col gap-1">
 <label className="text-xs text-gray-500">Description</label>
 <textarea
 value={form.description}
 onChange={e => setForm(prev => ({ ...prev, description: e.target.value }))}
 rows={3}
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500 resize-none"
 />
 </div>
 </div>
 <div className="flex gap-3">
 <button type="submit" className="bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg px-4 py-2 text-sm transition">
 {editingId ? 'Update' : 'Add'}
 </button>
 <button type="button" onClick={resetForm} className="text-sm text-gray-400 hover:text-white transition">
 Cancel
 </button>
 </div>
 </form>
 )}

 {/* List */}
 {experiences.length === 0 && !adding && (
 <p className="text-sm text-gray-600">No work experience added yet</p>
 )}
 <div className="flex flex-col gap-4">
 {experiences.map(exp => (
 <div key={exp._id} className="flex items-start justify-between gap-4 pb-4 border-b border-gray-800 last:border-0">
 <div className="flex-1 min-w-0">
 <div className="flex items-center gap-2">
 <p className="text-sm font-medium text-white">{exp.role}</p>
 {exp.source === 'linkedin' && (
 <span className="text-xs bg-blue-900 text-blue-400 px-2 py-0.5 rounded-full">LinkedIn</span>
 )}
 </div>
 <p className="text-xs text-gray-400 mt-0.5">{exp.company}</p>
 <p className="text-xs text-gray-600 mt-0.5">
 {exp.startDate} — {exp.current ? 'Present' : exp.endDate}
 </p>
 {exp.description && (
 <p className="text-xs text-gray-500 mt-2 line-clamp-2">{exp.description}</p>
 )}
 </div>
 <div className="flex gap-3 flex-shrink-0">
 <button onClick={() => handleEdit(exp)} className="text-xs text-gray-400 hover:text-white transition">Edit</button>
 <button onClick={() => handleDelete(exp._id)} className="text-xs text-gray-400 hover:text-red-400 transition">Delete</button>
 </div>
 </div>
 ))}
 </div>
 </div>
 )
}

import { useState, useEffect } from "react";
import { uploadFiles, getDocuments, deleteDocument } from "../services/upload";
import { DOCUMENT_TYPES, type DocumentType } from "../constants/document-types";
import { getFileUrl } from "../utils/url";

import { useToast } from "../context/ToastContext";
interface UploadedFile {
 _id: string;
 originalname: string;
 filename: string;
 size: number;
 mimetype: string;
 name: string;
 type: string;
}

const fileIcon = (mimetype?: string) => {
 if (!mimetype) return "📎";
 if (mimetype === "application/pdf") return "📄";
 if (mimetype.includes("word")) return "📝";
 if (mimetype.includes("image")) return "🖼️";
 return "📎";
};

export default function Upload() {
 const [files, setFiles] = useState<UploadedFile[]>([]);
 const [name, setName] = useState("");
 const [type, setType] = useState<DocumentType>(DOCUMENT_TYPES[0]);
 const [selectedFile, setSelectedFile] = useState<FileList | null>(null);
 const [selectedFileName, setSelectedFileName] = useState<string | null>(null);
 const [loading, setLoading] = useState(false);

 useEffect(() => {
 getDocuments().then((res) => setFiles(res.data.data));
 }, []);

 const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
 if (!e.target.files) return;
 setSelectedFile(e.target.files);
 setSelectedFileName(e.target.files[0].name);
 };

 // inside component
 const { showToast } = useToast();

 // update handleSubmit
 const handleSubmit = async (e: React.FormEvent) => {
 e.preventDefault();
 if (!selectedFile) return;
 setLoading(true);
 try {
 const res = await uploadFiles(selectedFile, name, type);
 setFiles((prev) => [...prev, ...res.data.data]);
 setName("");
 setType(DOCUMENT_TYPES[0]);
 setSelectedFile(null);
 setSelectedFileName(null);
 showToast("Document uploaded successfully");
 } catch (err) {
 showToast("Failed to upload document", "error");
 } finally {
 setLoading(false);
 }
 };

 // update handleDelete
 const handleDelete = async (_id: string) => {
 try {
 await deleteDocument(_id);
 setFiles((prev) => prev.filter((f) => f._id !== _id));
 showToast("Document deleted");
 } catch (err) {
 showToast("Failed to delete document", "error");
 }
 };

 return (
 <div className="min-h-screen bg-gray-950 text-white p-8">
 <div className="max-w-2xl mx-auto">
 <div className="mb-8">
 <h2 className="text-xl font-semibold">Reference Documents</h2>
 <p className="text-sm text-gray-500 mt-1">
 Upload documents used as reference for CV generation
 </p>
 </div>

 {/* Upload Form */}
 <form
 onSubmit={handleSubmit}
 className="bg-gray-900 rounded-2xl p-6 mb-8"
 >
 <h3 className="text-sm font-medium text-gray-300 mb-4">
 Add Document
 </h3>

 <div className="grid grid-cols-2 gap-4 mb-4">
 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">Document Name</label>
 <input
 type="text"
 value={name}
 onChange={(e) => setName(e.target.value)}
 placeholder="e.g. My Resume 2024"
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-indigo-500"
 />
 </div>

 <div className="flex flex-col gap-1">
 <label className="text-xs text-gray-500">Document Type</label>
 <select
 value={type}
 onChange={(e) => setType(e.target.value as DocumentType)}
 className="bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
 >
 {DOCUMENT_TYPES.map((t) => (
 <option key={t}>{t}</option>
 ))}
 </select>
 </div>
 </div>

 <div className="flex flex-col gap-1 mb-4">
 <label className="text-xs text-gray-500">File</label>
 <label className="border-2 border-dashed border-gray-700 rounded-xl p-5 flex items-center gap-4 cursor-pointer hover:border-indigo-500 transition">
 <span className="text-2xl">📎</span>
 <div>
 {selectedFileName ? (
 <p className="text-sm text-white">{selectedFileName}</p>
 ) : (
 <>
 <p className="text-sm text-gray-400">
 Click to select a file
 </p>
 <p className="text-xs text-gray-600 mt-0.5">
 PDF, DOC, DOCX, PNG, JPG up to 2MB
 </p>
 </>
 )}
 </div>
 <input
 type="file"
 accept=".pdf,.doc,.docx,image/*"
 onChange={handleFileChange}
 className="hidden"
 />
 </label>
 </div>

 <button
 type="submit"
 disabled={loading || !selectedFile || !name}
 className="bg-indigo-600 hover:bg-indigo-500 disabled:opacity-40 disabled:cursor-not-allowed text-white rounded-lg px-5 py-2 text-sm font-medium transition"
 >
 {loading ? "Uploading..." : "Upload Document"}
 </button>
 </form>

 {/* File List */}
 {files.length > 0 && (
 <div>
 <h3 className="text-sm font-medium text-gray-400 mb-3">
 Uploaded ({files.length})
 </h3>
 <div className="flex flex-col gap-2">
 {files.map((f) => (
 <div
 key={f._id}
 className="bg-gray-900 rounded-xl px-5 py-4 flex items-center gap-4"
 >
 <span className="text-2xl">{fileIcon(f.mimetype)}</span>
 <div className="flex-1 min-w-0">
 <p className="text-sm font-medium text-white truncate">
 {f.name || f.originalname}
 </p>
 <p className="text-xs text-gray-500 mt-0.5">
 {f.type} · {(f.size / 1024).toFixed(1)} KB
 </p>
 </div>
 <span className="text-xs bg-gray-800 text-gray-400 px-2 py-1 rounded-md">
 {f.type}
 </span>
 <a
 href={getFileUrl(f.filename)}
 target="_blank"
 rel="noreferrer"
 className="text-xs text-indigo-400 hover:text-indigo-300 transition"
 >
 View
 </a>
 <button
 onClick={() => handleDelete(f._id)}
 className="text-gray-600 hover:text-red-400 text-xs transition ml-2"
 >
 ✕
 </button>
 </div>
 ))}
 </div>
 </div>
 )}
 </div>
 </div>
 );
}

